   252→    /// <summary>
   253→    /// Edit a teamMember
   254→    /// </summary>
   255→    /// <param name="model"></param>
   256→    /// <returns></returns>
   257→    [HttpPost]
   258→    [ValidateAntiForgeryToken]
   259→    [MultipleButtonAction(Name = "action", Argument = "Edit")]
   260→    [Authorize(Roles = "BF Administrator,BF Manage User Password,BF User Manager (Training)")]
   261→    public ActionResult Edit(ApplicationUserModel model)
   262→    {
   263→      model.Roles = db.Roles.Select(x => new ApplicationRoleModel
   264→      {
   265→        Id = x.Id,
   266→        Name = x.Name
   267→      }).ToList();
   268→
   269→      if (ModelState.IsValid)
   270→      {
   271→        var user = userService.FindById(model.Id);
   272→
   273→        if (user == null)
   274→        {
   275→          this.NotifyError("User not found.");
   276→          return RedirectToAction("Index");
   277→        }
   278→
   279→        var oldRoles = userService.GetRoles(model.Id).ToArray();
   280→        var newRoles = model.SelectedRoleNames;
   281→
   282→        user.IsActive = model.IsActive;
   283→        user.UserName = user.UserName;
   284→        user.Email = model.Email;
   285→        user.EmailConfirmed = model.EmailConfirmed;
   286→        user.Description = model.Description;
   287→        user.PictureId = model.AvatarId;
   288→        user.Name = model.Name;
   289→        user.Surname = model.Surname;
   290→        user.Location = model.Location;
   291→        user.Badge = model.Badge;
   292→        user.NormalizedUserName = user.UserName;
   293→        user.ControlID = model.ControlID;
   294→        user.Facility_Key = model.Facility_Key;
   295→        user.Building_Key = model.Building_Key;
   296→        
   297→
   298→        if (Request.IsAuthenticated && (User.IsInRole("BF Administrator")))
   299→        {
   300→          newRoles = model.SelectedRoleNames;
   301→        }
   302→        else
   303→        {
   304→          newRoles = oldRoles;
   305→
   306→          user.IsActive = user.IsActive;
   307→          user.UserName = user.UserName;
   308→          user.Email = model.Email;
   309→          user.EmailConfirmed = model.EmailConfirmed;
   310→          user.Description = model.Description;
   311→          user.PictureId = model.AvatarId;
   312→          user.Name = user.Name;
   313→          user.Surname = user.Surname;
   314→          user.Location = user.Location;
   315→          user.Badge = model.Badge;
   316→          user.NormalizedUserName = user.UserName;
   317→          user.ControlID = model.ControlID;
   318→          user.Facility_Key = model.Facility_Key;
   319→          user.Building_Key = model.Building_Key;
   320→
   321→        }
   322→       
   323→
   324→        #region AddOrRemoveRoles
   325→        try
   326→        {
   327→          var rolesToRemove = oldRoles.Except(newRoles);
   328→          foreach (var role in rolesToRemove)
   329→            userService.RemoveFromRole(user.Id, role);
   330→
   331→          var rolesToAdd = newRoles.Except(oldRoles);
   332→          foreach (var role in rolesToAdd)
   333→            userService.AddToRole(user.Id, role);
   334→        }
   335→        catch
   336→        {
   337→
   338→        }
   339→        #endregion AddOrRemoveRoles
   340→
   341→        var result = userService.Update(user);
   342→        if (result.Succeeded)
   343→          this.NotifySuccess("Successfully saved.");
   344→        else
   345→          this.NotifyError("User can not saved!");
   346→
   347→        return RedirectToAction("Edit", new { id = model.Id });
   348→      }
   349→
   350→      return View(model);
   351→    }
