   356→    [Authorize(Roles = "BF User Add Image,BF User Manager (Training)")]
   357→    [HttpPost]
   358→    public ActionResult UploadFile()
   359→    {
   360→      string name = "";
   361→      // Checking no of files injected in Request object  
   362→
   363→      int test = Request.Files.Count;
   364→      if (Request.Files.Count > 0)
   365→      {
   366→        try
   367→        {
   368→          //  Get all files from Request object  
   369→          HttpPostedFileBase fileBase = Request.Files["file_name"];
   370→          HttpFileCollectionBase files = Request.Files;
   371→          string resultado = "";
   372→          for (int i = 0; i < files.Count; i++)
   373→          {
   374→            //string path = AppDomain.CurrentDomain.BaseDirectory + "Uploads/";
   375→            string filename = Path.GetFileName(Request.Files[i].FileName);
   376→            HttpPostedFileBase file = files[i];
   377→            string fname;
   378→            string fext;
   379→
   380→            // Checking for Internet Explorer  
   381→            if (Request.Browser.Browser.ToUpper() == "IE" || Request.Browser.Browser.ToUpper() == "INTERNETEXPLORER")
   382→            {
   383→              string[] testfiles = file.FileName.Split(new char[] { '\\' });
   384→              fname = testfiles[testfiles.Length - 1];
   385→            }
   386→            else
   387→            {
   388→              fname = file.FileName;
   389→            }
   390→            fext = Path.GetExtension(fname);
   391→
   392→
   393→            if (Firstronic.Framework.Upload.Upload.IsValidExtension(fext) && Firstronic.Framework.Upload.Upload.IsValidName(fname))
   394→            {
   395→
   396→              int id = 0;
   397→
   398→              try
   399→              {
   400→                id = Firstronic.Framework.Functions.Queries.GetNextIDFromQuery("Common_Files_Uploaded", "FileID");
   401→              }
   402→              catch (Exception ex)
   403→              {
   404→                ViewBag.Message = "ERROR:" + ex.Message.ToString();
   405→              }
   406→              name = id + "_" + 0 + fext;
   407→              SqlParameter[] parameters = new SqlParameter[]{
   408→                        new SqlParameter("@FileName",SqlDbType.NVarChar){Value = name},
   409→                        new SqlParameter("@Extension",SqlDbType.NVarChar){Value = fext},
   410→                };
   411→
   412→              //var result = db.ExecuteInsertCommand($@"", parameters);
   413→
   414→              var result_Update = db.ExecuteInsertCommand(@"INSERT INTO Common_Files_Uploaded  ([FileName],Extension) VALUES (@FileName,@Extension)", parameters);
   415→              // Get the complete folder path and store the file inside it.  
   416→              fname = Path.Combine(Server.MapPath("~/UploadedFiles/Users"), name);
   417→              file.SaveAs(fname);
   418→
   419→              resultado = name;
   420→
   421→
   422→            }
   423→
   424→          }
   425→          // Returns message that successfully uploaded  
   426→          return Json(resultado);
   427→        }
   428→        catch (Exception ex)
   429→        {
   430→          ViewBag.Message = "ERROR:" + ex.Message.ToString();
   431→          return Json("");
   432→        }
   433→      }
   434→      else
   435→      {
   436→        return Json("");
   437→      }
   438→    }
