    //===============================================================
    // Create or Edit
    //===============================================================
    [Authorize(Roles = "BF Administrator")]
    public ActionResult Create()
    {
      var model = new ApplicationUserModel();

      var roles = db.Roles.Select(x => new ApplicationRoleModel
      {
        Id = x.Id,
        Name = x.Name
      }).OrderBy(x => x.Name).ToList();

      model.Roles = roles;

      // Load facilities for dropdown
      model.FacilityList = Firstronic.Framework.Functions.Queries.GetSelectedFromQuery(
        "SELECT [Facility_Key],[Facility_Name] FROM [Common_Facilities]");

      // Load buildings for dropdown
      model.BuildingList = Firstronic.Framework.Functions.Queries.GetSelectedFromQuery(
        "SELECT [Building_Key],CONCAT([Building_Code],' - ',[Name]) as Name FROM [Common_Building] ORDER BY [Building_Code]");

      return View(model);
    }

    /// <summary>
    /// Create a Role
    /// </summary>
    /// <param name="model"></param>
    /// <returns></returns>
    [HttpPost]
    [ValidateInput(false)]
    [ValidateAntiForgeryToken]
    [MultipleButtonAction(Name = "action", Argument = "Create")]
    [Authorize(Roles = "BF Administrator")]
    public ActionResult Create(ApplicationUserModel model)
    {
      if (ModelState.IsValid)
      {

        var user = userService.FindByName(model.UserName);

        if (user == null)
        {
          user = new ApplicationUser
          {
            UserName = model.UserName,
            NormalizedUserName = model.UserName,
            NormalizedEmail = !string.IsNullOrWhiteSpace(model.UserName) ? model.UserName.ToUpperInvariant() : null,
            Name = !string.IsNullOrWhiteSpace(model.Name) ? model.Name : null,
            Surname = !string.IsNullOrWhiteSpace(model.Surname) ? model.Surname : null,
            Location = !string.IsNullOrWhiteSpace(model.Location) ? model.Location : null,
            Badge = !string.IsNullOrWhiteSpace(model.Badge) ? model.Badge : null,
            EmailConfirmed = true,
            Building_Key = model.Building_Key,
            Facility_Key = model.Facility_Key ?? 0,
            IsActive = true
          };
          userService.Create(user, model.Password);
        }

        if (user == null)
        {
          throw new Exception("The password is probably not strong enough!");
        }
        else
        {
          return RedirectToAction("Edit", new { Id = user.Id });
        }
      }

      return View(model);
    }


    [Authorize]
    public ActionResult Edit(string id)
    {

      bool continuetopage = false;

      if (Request.IsAuthenticated && (User.IsInRole("BF Administrator") || User.IsInRole("BF User Manager (Training)")))
      {
        continuetopage = true;
      }
      else
      {
        if (Request.IsAuthenticated && User.IsInRole("BF Administrator") == false)
        {
          if (User.Identity.GetUserId() == id)
          {
            continuetopage = true;
          }
        }
      }

      if (continuetopage)
      {
        var user = userService.GetById(id);
        if (user == null)
        {
          this.NotifyError("User not found.");
          return RedirectToAction("Index");
        }

        var roles = db.Roles.Select(x => new ApplicationRoleModel
        {
          Id = x.Id,
          Name = x.Name
        }).OrderBy(x => x.Name).ToList();

        var model = new ApplicationUserModel
        {
          Id = user.Id,
          Name = user.Name,
          UserName = user.UserName,
          Email = user.Email,
          EmailConfirmed = user.EmailConfirmed,
          IsActive = user.IsActive,
          AvatarId = user.PictureId,
          Description = user.Description,
          Location = user.Location,
          Badge = user.Badge,
          Surname = user.Surname,
          Facility_Key = user.Facility_Key,
          Building_Key = user.Building_Key,
          Roles = roles,
          SelectedRoleNames = userService.GetRoles(user.Id).ToArray()
        };

        SqlParameter[] parameters = new SqlParameter[]{
          new SqlParameter("@Id",SqlDbType.NVarChar){Value = model.Id},
        };

        model.ControlID = Firstronic.Framework.Queries.GetIntFromQuery("Select ControlID from AspNetUsers WHERE ID=@Id", parameters);

        // Load facilities for dropdown
        model.FacilityList = Firstronic.Framework.Functions.Queries.GetSelectedFromQuery(
          "SELECT [Facility_Key],[Facility_Name] FROM [Common_Facilities]");

        // Load buildings for dropdown
        model.BuildingList = Firstronic.Framework.Functions.Queries.GetSelectedFromQuery(
          "SELECT [Building_Key],CONCAT([Building_Code],' - ',[Name]) as Name FROM [Common_Building] ORDER BY [Building_Code]");

        return View(model);
      }
      else
      {
        this.NotifyError("No allowed");
        return RedirectToAction("Index");
      }
    }

    /// <summary>
    /// Edit a teamMember
    /// </summary>
    /// <param name="model"></param>
    /// <returns></returns>
    [HttpPost]
    [ValidateAntiForgeryToken]
    [MultipleButtonAction(Name = "action", Argument = "Edit")]
    [Authorize(Roles = "BF Administrator,BF Manage User Password,BF User Manager (Training)")]
    public ActionResult Edit(ApplicationUserModel model)
    {
      model.Roles = db.Roles.Select(x => new ApplicationRoleModel
      {
        Id = x.Id,
        Name = x.Name
      }).ToList();

      if (ModelState.IsValid)
      {
        var user = userService.FindById(model.Id);

        if (user == null)
        {
          this.NotifyError("User not found.");
          return RedirectToAction("Index");
        }

        var oldRoles = userService.GetRoles(model.Id).ToArray();
        var newRoles = model.SelectedRoleNames;

        user.IsActive = model.IsActive;
        user.UserName = user.UserName;
        user.Email = model.Email;
        user.EmailConfirmed = model.EmailConfirmed;
        user.Description = model.Description;
        user.PictureId = model.AvatarId;
        user.Name = model.Name;
        user.Surname = model.Surname;
        user.Location = model.Location;
        user.Badge = model.Badge;
        user.NormalizedUserName = user.UserName;
        user.ControlID = model.ControlID;
        user.Facility_Key = model.Facility_Key;
        user.Building_Key = model.Building_Key;


        if (Request.IsAuthenticated && (User.IsInRole("BF Administrator")))
        {
          newRoles = model.SelectedRoleNames;
        }
        else
        {
          newRoles = oldRoles;

          user.IsActive = user.IsActive;
          user.UserName = user.UserName;
          user.Email = model.Email;
          user.EmailConfirmed = model.EmailConfirmed;
          user.Description = model.Description;
          user.PictureId = model.AvatarId;
          user.Name = user.Name;
          user.Surname = user.Surname;
          user.Location = user.Location;
          user.Badge = model.Badge;
          user.NormalizedUserName = user.UserName;
          user.ControlID = model.ControlID;
          user.Facility_Key = model.Facility_Key;
          user.Building_Key = model.Building_Key;

        }


        #region AddOrRemoveRoles
        try
        {
          var rolesToRemove = oldRoles.Except(newRoles);
          foreach (var role in rolesToRemove)
            userService.RemoveFromRole(user.Id, role);

          var rolesToAdd = newRoles.Except(oldRoles);
          foreach (var role in rolesToAdd)
            userService.AddToRole(user.Id, role);
        }
        catch
        {

        }
        #endregion AddOrRemoveRoles

        var result = userService.Update(user);
        if (result.Succeeded)
          this.NotifySuccess("Successfully saved.");
        else
          this.NotifyError("User can not saved!");

        return RedirectToAction("Edit", new { id = model.Id });
      }

      return View(model);
    }

    //===============================================================
    // File Upload
    //===============================================================
    [Authorize(Roles = "BF User Add Image,BF User Manager (Training)")]
    [HttpPost]
    public ActionResult UploadFile()
    {
      string name = "";
      // Checking no of files injected in Request object  

      int test = Request.Files.Count;
      if (Request.Files.Count > 0)
      {
        try
        {
          //  Get all files from Request object  
          HttpPostedFileBase fileBase = Request.Files["file_name"];
          HttpFileCollectionBase files = Request.Files;
          string resultado = "";
          for (int i = 0; i < files.Count; i++)
          {
            //string path = AppDomain.CurrentDomain.BaseDirectory + "Uploads/";
            string filename = Path.GetFileName(Request.Files[i].FileName);
            HttpPostedFileBase file = files[i];
            string fname;
            string fext;

            // Checking for Internet Explorer  
            if (Request.Browser.Browser.ToUpper() == "IE" || Request.Browser.Browser.ToUpper() == "INTERNETEXPLORER")
            {
              string[] testfiles = file.FileName.Split(new char[] { '\\' });
              fname = testfiles[testfiles.Length - 1];
            }
            else
            {
              fname = file.FileName;
            }
            fext = Path.GetExtension(fname);


            if (Firstronic.Framework.Upload.Upload.IsValidExtension(fext) && Firstronic.Framework.Upload.Upload.IsValidName(fname))
            {

              int id = 0;

              try
              {
                id = Firstronic.Framework.Functions.Queries.GetNextIDFromQuery("Common_Files_Uploaded", "FileID");
              }
              catch (Exception ex)
              {
                ViewBag.Message = "ERROR:" + ex.Message.ToString();
              }
              name = id + "_" + 0 + fext;
              SqlParameter[] parameters = new SqlParameter[]{
                        new SqlParameter("@FileName",SqlDbType.NVarChar){Value = name},
                        new SqlParameter("@Extension",SqlDbType.NVarChar){Value = fext},
                };

              //var result = db.ExecuteInsertCommand($@"", parameters);

              var result_Update = db.ExecuteInsertCommand(@"INSERT INTO Common_Files_Uploaded  ([FileName],Extension) VALUES (@FileName,@Extension)", parameters);
              // Get the complete folder path and store the file inside it.  
              fname = Path.Combine(Server.MapPath("~/UploadedFiles/Users"), name);
              file.SaveAs(fname);

              resultado = name;


            }

          }
          // Returns message that successfully uploaded  
          return Json(resultado);
        }
        catch (Exception ex)
        {
          ViewBag.Message = "ERROR:" + ex.Message.ToString();
          return Json("");
        }
      }
      else
      {
        return Json("");
      }
    }

    [HttpPost]
