[MultipleButtonAction(Name = "action", Argument = "Create")]
[Authorize(Roles = "BF Administrator")]
public ActionResult Create(ApplicationUserModel model)
{
  if (ModelState.IsValid)
  {

    var user = userService.FindByName(model.UserName);

    if (user == null)
    {
      user = new ApplicationUser
      {
        UserName = model.UserName,
        NormalizedUserName = model.UserName,
        NormalizedEmail = !string.IsNullOrWhiteSpace(model.UserName) ? model.UserName.ToUpperInvariant() : null,
        Name = !string.IsNullOrWhiteSpace(model.Name) ? model.Name : null,
        Surname = !string.IsNullOrWhiteSpace(model.Surname) ? model.Surname : null,
        Location = !string.IsNullOrWhiteSpace(model.Location) ? model.Location : null,
        Badge = !string.IsNullOrWhiteSpace(model.Badge) ? model.Badge : null,
        EmailConfirmed = true,
        Building_Key = model.Building_Key,
        Facility_Key = model.Facility_Key ?? 0,
        IsActive = true
      };
      userService.Create(user, model.Password);
    }

