    public ActionResult ChangePassword(string username)
    {
      var model = new ChangePasswordViewModel();

      SqlParameter[] parameters = new SqlParameter[]{
          new SqlParameter("@username",SqlDbType.NVarChar){Value = username},
        };

      var userId = Firstronic.Framework.Queries.GetStringFromQuery("Select ID from AspNetUsers WHERE username=@username", parameters);

      bool continuetopage = false;

      if (Request.IsAuthenticated && (User.IsInRole("BF Administrator") || User.IsInRole("BF User Manager (Training)")))
      {
        continuetopage = true;
      }
      else
      {
        if (Request.IsAuthenticated && User.IsInRole("BF Administrator") == false)
        {
          if (User.Identity.GetUserId() == userId)
          {
            continuetopage = true;
          }
        }
      }

      if (continuetopage)
      {
        var user = userService.GetById(userId);
        model.UserName = user.UserName;

        return View(model);
      }
      else
      {
        this.NotifyError("No allowed");
        return RedirectToAction("Index");
      }
    }

    [HttpPost]
    [ValidateAntiForgeryToken]
    public ActionResult ChangePassword(ChangePasswordViewModel model)
    {
      if (!ModelState.IsValid)
      {
        return View(model);
      }

      string userName = model.UserName;

      var user = userService.FindByName(userName);
      if (user.PasswordHash != null)
      {
        userService.RemovePassword(user.Id);
      }

      userService.AddPassword(user.Id, model.NewPassword);

      this.NotifySuccess("Successfully changed.");

      return RedirectToAction("Print", "Printer", new { Area="Utils", UserName = userName });
    }


