using System;
using System.IO;
using System.Web;
using System.Web.Mvc;
using System.Web.Routing;
using Firstronic.Framework.Cache;
using Firstronic.Framework.Core;
using Firstronic.Framework.Helpers;
using Firstronic.Framework.Languages;
using Firstronic.Framework.UI;
using HtmlHelper = System.Web.Mvc.HtmlHelper;

namespace Firstronic.Framework.Controllers
{
  public abstract class BaseController : Controller
  {
    protected override void Initialize(RequestContext requestContext)
    {
      base.Initialize(requestContext);
    }

    protected override IAsyncResult BeginExecuteCore(AsyncCallback callback, object state)
    {
      string lang = null;
      HttpCookie langCookie = Request.Cookies["culture"];
      if (langCookie != null)
      {
        lang = langCookie.Value;
      }
      else
      {
        var userLanguage = Request.UserLanguages;
        var userLang = userLanguage != null ? userLanguage[0] : "";
        if (userLang != "")
        {
          lang = userLang;
        }
        else
        {
          lang = LanguageMang.GetDefaultLanguage();
        }
      }
      new LanguageMang().SetLanguage(lang);
      return base.BeginExecuteCore(callback, state);
    }

    #region Redirect

    [AllowAnonymous]
    public virtual ActionResult Error()
    {
      return Redirect("Pages/Error.html");
    }

    [AllowAnonymous]
    public virtual ActionResult NotFound()
    {
      return Redirect("Pages/NotFound.html");
    }

    [AllowAnonymous]
    public virtual ActionResult NotActive()
    {
      return Redirect("Pages/NotFound.html");
    }

    public virtual ActionResult HomePage()
    {
      return RedirectToAction("Index", "Home");
    }

    #endregion Redirect

    public ActionResult ClearCache()
    {
      Engine.Resolve<ICacheManager>().Clear();
      NotifySuccess("Cache cleared.");

      string urlReferer = WebHelper.GetUrlReferrer;
      if (String.IsNullOrEmpty(urlReferer))
        return RedirectToAction("Index", "Home");
      else
        return Redirect(urlReferer);
    }

    public ActionResult NoPermission()
    {
      return View();
    }

    public virtual void NotifySuccess(string message)
    {
      TempData["NotifySuccess"] = HtmlHelper.Fst().Popup().Position(PopupPosition.TopRight).Slide(PopupSlide.Down)
                                       .AutoShow()
                                       .Message(message)
                                       .BgColor(Utilities.BootstrapColor.Success)
                                       .ToHtmlString();
    }

    public virtual void NotifyError(string message)
    {
      TempData["NotifyError"] = HtmlHelper.Fst().Popup().Position(PopupPosition.TopRight).Slide(PopupSlide.Down)
                                   .AutoShow()
                                   .Message(message)
                                   .BgColor(Utilities.BootstrapColor.Danger)
                                   .ToHtmlString();
    }

    public virtual void NotifyInfo(string message)
    {
      TempData["NotifyInfo"] = HtmlHelper.Fst().Popup().Position(PopupPosition.TopRight).Slide(PopupSlide.Down)
                                    .AutoShow()
                                    .Message(message)
                                    .BgColor(Utilities.BootstrapColor.Info)
                                    .ToHtmlString();
    }

    public virtual void NotifyWarning(string message)
    {
      TempData["NotifyWarning"] = HtmlHelper.Fst().Popup().Position(PopupPosition.TopRight).Slide(PopupSlide.Down)
                                    .AutoShow()
                                    .Message(message)
                                    .BgColor(Utilities.BootstrapColor.Warning)
                                    .ToHtmlString();
    }

    /// <summary>
    /// Fake HtmlHelper
    /// </summary>
    public HtmlHelper HtmlHelper
    {
      get
      {
        return new HtmlHelper(new ViewContext(ControllerContext,
            new WebFormView(ControllerContext, "omg"),
            new ViewDataDictionary(),
            new TempDataDictionary(),
            new StringWriter()), new ViewPage());
      }
    }
  }
}

